function autoClearSession() {
    const sessionDir = './furina';
    const tempDir = './temp'; // Definisi folder temp
    const clearInterval = 4 * 60 * 60 * 1000; // 4 Jam
    
    setInterval(async () => {
        try {
            const files = fs.readdirSync(sessionDir);
            const filteredFiles = files.filter(file => 
                file.startsWith('pre-key') ||
                file.startsWith('sender-key') ||
                file.startsWith('session-') ||
                file.startsWith('app-state')
            );

            if (filteredFiles.length > 0) {
                console.log(chalk.yellow.bold(`ЁЯУВ [AUTO CLEAN] Starting session cleanup... ЁЯЧГя╕П`));
                filteredFiles.forEach(file => {
                    fs.unlinkSync(path.join(sessionDir, file));
                });
                console.log(chalk.green.bold(`ЁЯЧГя╕П [AUTO CLEAN] Successfully removed ${filteredFiles.length} session files! ЁЯУВ`));
            } else {
                console.log(chalk.blue.bold(`ЁЯУВ [AUTO CLEAN] No session files to clean. ЁЯУС`));
            }

            if (fs.existsSync(tempDir)) {
                const tempFiles = fs.readdirSync(tempDir);
                
                if (tempFiles.length > 0) {
                    console.log(chalk.magenta.bold(`ЁЯЧСя╕П [TEMP CLEAN] Found files in temp, cleaning... ЁЯз╣`));
                    
                    tempFiles.forEach(file => {
                        fs.unlinkSync(path.join(tempDir, file));
                    });

                    console.log(chalk.cyan.bold(`ЁЯЧСя╕П [TEMP CLEAN] Successfully deleted ${tempFiles.length} files from temp folder! тЬи`));
                } else {
                    console.log(chalk.blue.bold(`ЁЯЧСя╕П [TEMP CLEAN] Temp folder is already empty. тЬЕ`));
                }
            }

        } catch (error) {
            console.error(chalk.red.bold(`ЁЯУС [AUTO CLEAN ERROR]`), chalk.red.bold(error));
        }
    }, clearInterval);
}

autoClearSession();